// Extract chat_id from error execution data
const errData = $json.execution || {};
const workflowId = String(errData.workflowId || '');
const errorMsg = String(errData.error?.message || 'Unknown error');
const lastNode = String(errData.lastNodeExecuted || '');

// Try to extract chat_id from the error's run data
let chatId = '';
try {
  const runData = errData.data?.resultData?.runData || {};
  // Try Edit Fields first
  const editItems = runData['Edit Fields'];
  if (editItems?.[0]?.data?.main?.[0]?.[0]?.json?.chat_id) {
    chatId = String(editItems[0].data.main[0][0].json.chat_id);
  }
  // Try WhatsApp Trigger
  if (!chatId) {
    const waItems = runData['WhatsApp Trigger'];
    if (waItems?.[0]?.data?.main?.[0]?.[0]?.json?.chat_id) {
      chatId = String(waItems[0].data.main[0][0].json.chat_id);
    }
  }
} catch(e) {}

return [{ json: {
  chat_id: chatId,
  error_msg: errorMsg,
  last_node: lastNode,
  workflow_id: workflowId,
  has_chat_id: !!chatId,
} }];

